-- Hand-authored initial migration (Phase 1).
--
-- This is normally auto-generated by `prisma migrate dev`, but two columns in
-- schema.prisma use Postgres-native types Prisma can't generate DDL for on its
-- own (Workspace.path -> ltree, DocumentChunk.embedding -> vector(768)), so the
-- whole baseline is hand-written here to keep it internally consistent. Column
-- types/names/nullability mirror schema.prisma model-for-model; foreign keys are
-- only added where schema.prisma declares an actual `@relation` (Conversation,
-- RetentionPolicy, LegalHold, AuditLog, SearchQuery, and DocumentTag deliberately
-- store plain string ids with no relation/FK, exactly as modeled).

-- Extensions are created here (not just in db/init/01-extensions.sql) because
-- Prisma's shadow database (used by `prisma migrate dev` to diff future schema
-- changes) is a fresh database that never runs the docker-entrypoint init script.
CREATE EXTENSION IF NOT EXISTS "vector";
CREATE EXTENSION IF NOT EXISTS "ltree";
CREATE EXTENSION IF NOT EXISTS "pg_trgm";

-- CreateEnum
CREATE TYPE "WorkspaceType" AS ENUM ('ORG', 'DEPARTMENT', 'CLIENT');
CREATE TYPE "Role" AS ENUM ('FOUNDER', 'ADMIN', 'MANAGER', 'TEAM_MEMBER');
CREATE TYPE "DocumentStatus" AS ENUM ('PROCESSING', 'READY', 'FAILED', 'SOFT_DELETED');

-- CreateTable
CREATE TABLE "Workspace" (
    "id" TEXT NOT NULL,
    "parentWorkspaceId" TEXT,
    "type" "WorkspaceType" NOT NULL,
    "name" TEXT NOT NULL,
    -- Deviation from schema.prisma's `String`: real Postgres type is `ltree`, a
    -- materialized-path type with native ancestor/descendant operators (`@>`/`<@`)
    -- used by RBAC role inheritance (lib/rbac.ts). Postgres's ltree extension
    -- registers an assignment cast to/from `text`, so Prisma Client's normal
    -- string read/writes on this field keep working unchanged.
    "path" ltree NOT NULL,
    "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updatedAt" TIMESTAMP(3) NOT NULL,

    CONSTRAINT "Workspace_pkey" PRIMARY KEY ("id")
);

-- CreateTable
CREATE TABLE "User" (
    "id" TEXT NOT NULL,
    "googleId" TEXT NOT NULL,
    "email" TEXT NOT NULL,
    "name" TEXT,
    "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,

    CONSTRAINT "User_pkey" PRIMARY KEY ("id")
);

-- CreateTable
CREATE TABLE "RoleAssignment" (
    "id" TEXT NOT NULL,
    "userId" TEXT NOT NULL,
    "workspaceId" TEXT NOT NULL,
    "role" "Role" NOT NULL,
    "grantedById" TEXT,
    "grantedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "expiresAt" TIMESTAMP(3),

    CONSTRAINT "RoleAssignment_pkey" PRIMARY KEY ("id")
);

