-- CreateTable
CREATE TABLE "Document" (
    "id" TEXT NOT NULL,
    "workspaceId" TEXT NOT NULL,
    "folderId" TEXT,
    "uploaderId" TEXT NOT NULL,
    "sourceType" TEXT NOT NULL,
    "storagePath" TEXT NOT NULL,
    "displayTitle" TEXT NOT NULL,
    "originalFilename" TEXT NOT NULL,
    "documentDate" TIMESTAMP(3),
    "status" "DocumentStatus" NOT NULL DEFAULT 'PROCESSING',
    -- Added beyond today's schema.prisma (see cross-cutting decisions in the
    -- Phase 1-4 plan) so the worker can record why ingestion failed. schema.prisma
    -- is updated in this same phase to declare this field.
    "processingError" TEXT,
    "deletedAt" TIMESTAMP(3),
    "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updatedAt" TIMESTAMP(3) NOT NULL,

    CONSTRAINT "Document_pkey" PRIMARY KEY ("id")
);

-- CreateTable
CREATE TABLE "DocumentVersion" (
    "id" TEXT NOT NULL,
    "documentId" TEXT NOT NULL,
    "versionNumber" INTEGER NOT NULL,
    "storagePath" TEXT NOT NULL,
    "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,

    CONSTRAINT "DocumentVersion_pkey" PRIMARY KEY ("id")
);

-- CreateTable
CREATE TABLE "DocumentChunk" (
    "id" TEXT NOT NULL,
    "documentId" TEXT NOT NULL,
    "text" TEXT NOT NULL,
    -- Deviation from a plain Prisma-generated column: pgvector type, matches
    -- OLLAMA_EMBEDDING_MODEL=nomic-embed-text's 768-dim output. Written only via
    -- raw SQL (worker/lib/db.ts) since Prisma Client can't write an
    -- Unsupported(...) column.
    "embedding" vector(768),
    "embeddingModel" TEXT,
    "embeddingModelVersion" TEXT,
    "pageOrSectionRef" TEXT,
    "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,

    CONSTRAINT "DocumentChunk_pkey" PRIMARY KEY ("id")
);

