-- CreateTable
-- Deliberately has no FK/relation to User/Document/Workspace (see the comment on
-- the AuditLog model in schema.prisma) so deleting content or users can never
-- delete or orphan-cascade audit history.
CREATE TABLE "AuditLog" (
    "id" TEXT NOT NULL,
    "actorId" TEXT,
    "actionType" TEXT NOT NULL,
    "resourceType" TEXT,
    "resourceSnapshot" JSONB,
    "workspaceId" TEXT,
    "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "metadata" JSONB,

    CONSTRAINT "AuditLog_pkey" PRIMARY KEY ("id")
);

-- CreateIndex
CREATE INDEX "Workspace_parentWorkspaceId_idx" ON "Workspace"("parentWorkspaceId");
-- GiST index required for ltree ancestor/descendant operators (`@>`, `<@`) used
-- by lib/rbac.ts's role-inheritance queries to run efficiently.
CREATE INDEX "Workspace_path_idx" ON "Workspace" USING GIST ("path");

