CREATE UNIQUE INDEX "User_googleId_key" ON "User"("googleId");
CREATE UNIQUE INDEX "User_email_key" ON "User"("email");

-- CreateIndex
CREATE UNIQUE INDEX "RoleAssignment_userId_workspaceId_key" ON "RoleAssignment"("userId", "workspaceId");
CREATE INDEX "RoleAssignment_workspaceId_idx" ON "RoleAssignment"("workspaceId");

