-- CreateIndex
-- Not Prisma-relation-derived (Conversation has no @relation fields) but added
-- deliberately: app/api/chat/route.ts looks up "the conversation for this
-- (userId, workspaceId)" on every chat request.
CREATE INDEX "Conversation_userId_workspaceId_idx" ON "Conversation"("userId", "workspaceId");

-- CreateIndex
CREATE INDEX "Message_conversationId_idx" ON "Message"("conversationId");

-- CreateIndex
CREATE INDEX "MessageCitation_messageId_idx" ON "MessageCitation"("messageId");

