-- Not Prisma-relation-derived (AuditLog deliberately has none) but added since
-- audit history is always queried scoped to a workspace or actor.
CREATE INDEX "AuditLog_workspaceId_idx" ON "AuditLog"("workspaceId");
CREATE INDEX "AuditLog_actorId_idx" ON "AuditLog"("actorId");

-- AddForeignKey
-- RESTRICT: block deleting a workspace that still has child workspaces, rather
-- than silently cascading a delete through an entire org subtree.
ALTER TABLE "Workspace" ADD CONSTRAINT "Workspace_parentWorkspaceId_fkey" FOREIGN KEY ("parentWorkspaceId") REFERENCES "Workspace"("id") ON DELETE RESTRICT ON UPDATE CASCADE;

